    if (this.state === 'HALF_OPEN') {
      if (this.probeInFlight) {
        throw new CircuitOpenError()
      }
      this.probeInFlight = true
    }

    try {
      const result = await fn()
      this.onSuccess()
      return result
    } catch (err) {
      this.onFailure()
      throw err
    } finally {
      if (this.state === 'CLOSED') {
        this.probeInFlight = false
      }
    }
  }

  private onSuccess(): void {
    this.failureCount = 0
    this.state = 'CLOSED'
